def shout(fn):
    def wrapper(*args, **kwargs):
        result = fn(*args, **kwargs)
        return result.upper() + "!"
    return wrapper

@shout
def say_hi():
    return "hi"

print(say_hi())

def prefixed(prefix):
    def decorator(fn):
        def wrapper(*args, **kwargs):
            return prefix + fn(*args, **kwargs)
        return wrapper
    return decorator

@prefixed("[INFO] ")
def msg():
    return "started"

print(msg())
